input.script:
  // Start music otomatis
  const bgm = document.getElementById('bgm');
  bgm.play().catch(()=>{ /* browser mungkin blok autoplay */ });

  // LocalStorage untuk pesan
  let messages = JSON.parse(localStorage.getItem("loveMsgs")) || [];

  function render() {
    const box = document.getElementById("messages");
    box.innerHTML = "";
    messages.forEach(msg => {
      box.innerHTML += `
${msg}`;
    });
  }

  function saveMsg() {
    const input = document.getElementById("inputMsg");
    if(input.value.trim() !== "") {
      messages.push(input.value);
      localStorage.setItem("loveMsgs", JSON.stringify(messages));
      createStar();
      input.value = "";
      render();
    }
  }

  render();

  // Canvas untuk bintang
  const canvas = document.getElementById("starCanvas");
  const ctx = canvas.getContext("2d");
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;

  function createStar() {
    const x = Math.random() * canvas.width;
    const y = Math.random() * canvas.height;
    const r = Math.random() * 3 + 1;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fillStyle = "yellow";
    ctx.fill();
  }

  // Bintang acak otomatis
  setInterval(() => { createStar(); }, 500);

  // Hati jatuh
  setInterval(() => {
    const heart = document.createElement("div");
    heart.classList.add("heart");
    heart.innerHTML = "❤️";
    heart.style.left = Math.random() * 100 + "vw";
    heart.style.animationDuration = (Math.random() * 3 + 2) + "s";
    document.body.appendChild(heart);
    setTimeout(() => heart.remove(), 5000);
  }, 300);

  // Resize canvas otomatis
  window.addEventListener('resize', () => {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  });
